import{_ as e,o as t,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Understanding ERA in Diamond Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/era-explained.md","filePath":"analytics/era-explained.md"}'),i={name:"analytics/era-explained.md"};function d(s,a,o,l,h,u){return t(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="understanding-era-in-diamond-analytics" tabindex="-1">Understanding ERA in Diamond Analytics <a class="header-anchor" href="#understanding-era-in-diamond-analytics" aria-label="Permalink to &quot;Understanding ERA in Diamond Analytics&quot;">​</a></h1><h2 id="what-is-era" tabindex="-1">What is ERA? <a class="header-anchor" href="#what-is-era" aria-label="Permalink to &quot;What is ERA?&quot;">​</a></h2><p>Earned Run Average (ERA) measures how many earned runs a pitcher allows per game. Lower is better.</p><h2 id="standard-era-formula" tabindex="-1">Standard ERA Formula <a class="header-anchor" href="#standard-era-formula" aria-label="Permalink to &quot;Standard ERA Formula&quot;">​</a></h2><p>ERA = (Earned Runs ÷ Innings Pitched) × Game Innings</p><h2 id="age-appropriate-calculation" tabindex="-1">Age-Appropriate Calculation <a class="header-anchor" href="#age-appropriate-calculation" aria-label="Permalink to &quot;Age-Appropriate Calculation&quot;">​</a></h2><p>Diamond Analytics adjusts ERA based on your team level because youth games use fewer innings than professional baseball:</p><table tabindex="0"><thead><tr><th>Level</th><th>Game Innings</th><th>ERA Formula</th></tr></thead><tbody><tr><td>8U – 12U</td><td>6 innings</td><td>(ER ÷ IP) × 6</td></tr><tr><td>13U – 18U</td><td>7 innings</td><td>(ER ÷ IP) × 7</td></tr><tr><td>Middle School</td><td>7 innings</td><td>(ER ÷ IP) × 7</td></tr><tr><td>High School</td><td>7 innings</td><td>(ER ÷ IP) × 7</td></tr></tbody></table><p>The ERA label throughout the app indicates which calculation is being used — for example <strong>ERA (6-inn)</strong> or <strong>ERA (7-inn)</strong>.</p><h2 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h2><p>A pitcher who allows 2 earned runs over 3 innings has:</p><ul><li><strong>Standard (9-inn) ERA:</strong> 6.00</li><li><strong>Youth 7-inn ERA:</strong> 4.67</li><li><strong>Youth 6-inn ERA:</strong> 4.00</li></ul><p>Using age-appropriate innings gives a more accurate picture of performance relative to the game format actually being played.</p><h2 id="earned-vs-unearned-runs" tabindex="-1">Earned vs Unearned Runs <a class="header-anchor" href="#earned-vs-unearned-runs" aria-label="Permalink to &quot;Earned vs Unearned Runs&quot;">​</a></h2><p>Only <strong>earned runs</strong> count toward ERA. Runs that score due to errors are unearned and do not count. When logging pitching data, earnedRuns is recorded separately from total runs allowed.</p>',15)])])}const g=e(i,[["render",d]]);export{p as __pageData,g as default};
